#!/usr/bin/env bash
# run-a-pipeline-deal-review-manag.sh — Run a pipeline / deal review (manager side)（运营 pipeline / deal review——管理者侧） SOP walkthrough for B2B 大客户销售.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="B2B 大客户销售"
WORKFLOW="Run a pipeline / deal review (manager side)（运营 pipeline / deal review——管理者侧）"

usage() {
  cat <<EOF
run-a-pipeline-deal-review-manag.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./run-a-pipeline-deal-review-manag.sh             # interactive
  ./run-a-pipeline-deal-review-manag.sh --dry-run
  ./run-a-pipeline-deal-review-manag.sh --json
  ./run-a-pipeline-deal-review-manag.sh --explain
  ./run-a-pipeline-deal-review-manag.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "Run a pipeline / deal review (manager side)（运营 pipeline / deal review——管理者侧）" 工作流。

一句话: A manager's weekly inspection that finds *blind spots* in deals fast — not a box-checking recap. Done right it covers 10+ deals in 30 minutes and produces coaching, not theater. (evidence: [T03-S021, T03-S020])

入门 SOP 共 4 步, 失败模式自检 4 项。

相关心智模型:
  • 问 ⇄ 教 ⇄ 筛:三派第一性张力,资深人按层混用: 复杂销售的方法论分三派——诊断式提问(SPIN/Gap:「客户有答案,问到痛点不可否认为止」)⇄ 挑战式教学(Challenger:「客户对自己问题的认知是错的,用商业洞见 reframe」)⇄ 资格
  • 头号对手是「不决策」,不是竞品: 预测内丢单的最大去向不是输给对手,而是客户「什么都不做」——维持现状;且一旦购买意向形成,买方更怕「搞砸」(FOMU)而非「错过」(FOMO),所以晚期停滞要按「犹豫」处理(去风险),不是按「异议」处

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**Define stages + exit criteria** — establish what constitutes progress at each stage so \"stage\" means something. (evidence: [T03-S021])"
  "**Select big deals + strike-zone deals** — focus the review on high-value and decision-moment deals, not every opp. (evidence: [T03-S021])"
  "**Reps recap each stage in one sentence** — how the exit criteria were met + the plan for the next two stages (minimum recap). (evidence: [T03-S021])"
  "**Manager asks blind-spot questions** — for past stages probe the *method* of achievement; for future stages challenge the *viability* of the plan (\"rollercoaster attendant checking safety,\" not interrogator). (evidence: [T03-S021])"
)
declare -a FAILURE_MODES=(
  "**Box-checking deal review — checking that CRM fields are filled, not whether the deal is real**: produces compliance, not coaching. Avoid: ask blind-spot questions about *quality* (name the EB, prove the pain), enforce exit criteria. (evidence: [T03-S021, T03-S018])"
  "**10-minute recaps with a multitasking manager**: reviews 3-5 deals, teaches nothing. Avoid: one-sentence-per-stage recaps; aim for 10+ deals in 30 min. (evidence: [T03-S021])"
  "**No exit criteria → stages are meaningless**: reps self-assign stage by feel and the forecast is unanchored. Avoid: define exit criteria per stage and gate advancement on them. (evidence: [T03-S021])"
  "**AI flags used to nitpick scores instead of coach behavior → surveillance theater**: reps game the metrics, adoption becomes compliance. Avoid: use AI flags to *start* a coaching conversation, not to police talk-ratios. (evidence: [T03-S030])"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "run-a-pipeline-deal-review-manag-walkthrough"
fi
